-- Vincular automaticamente leads que já têm vendas no sistema
UPDATE public.leads_w3 l
SET is_cliente_educacao = true
WHERE EXISTS (
  SELECT 1 FROM public.vendas v
  WHERE lower(v.email) = lower(l.email)
  AND l.email IS NOT NULL
);
